import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { ResponsiveContainer, AreaChart, Area, YAxis } from 'recharts';
import { Bitcoin, Coins, CircleDot, Database, Smartphone, XCircle } from 'lucide-react';
import '../../styles/crypto.css';

const COIN_CONFIGS = {
  'BTCTRY': { name: 'BITCOIN', symbol: 'BTC', icon: Bitcoin, color: '#F7931A' },
  'ETHTRY': { name: 'ETHEREUM', symbol: 'ETH', icon: Coins, color: '#627EEA' },
  'SOLTRY': { name: 'SOLANA', symbol: 'SOL', icon: Smartphone, color: '#14F195' },
  'BNBTRY': { name: 'BINANCE COIN', symbol: 'BNB', icon: CircleDot, color: '#F3BA2F' },
  'ADATRY': { name: 'CARDANO', symbol: 'ADA', icon: Database, color: '#0033AD' },
  'XRPTRY': { name: 'XRP', symbol: 'XRP', icon: XCircle, color: '#FFFFFF' }
};

const CryptoBox = ({ coinData }) => {
  const config = COIN_CONFIGS[coinData.pair];
  const Icon = config.icon;
  const isPositive = coinData.dailyPercent >= 0;

  return (
    <div className="crypto-item-box">
      <div className="coin-left-section">
        <div className="coin-icon-wrapper" style={{ background: `linear-gradient(135deg, ${config.color}33, ${config.color}11)` }}>
          <Icon color={config.color} size={28} />
        </div>
        <div className="coin-details">
          <h3 className="coin-title">{config.name} ({config.symbol})</h3>
          <div className="price-info">
            <span className="coin-price">{parseFloat(coinData.last).toLocaleString('tr-TR')} ₺</span>
            <span className={`coin-change ${isPositive ? 'up' : 'down'}`}>
              {isPositive ? '+' : ''}{coinData.dailyPercent.toFixed(2)}%
            </span>
          </div>
        </div>
      </div>

      <div className="coin-right-section">
        <ResponsiveContainer width="100%" height={60}>
          <AreaChart data={coinData.history}>
            <defs>
              <linearGradient id={`color-${config.symbol}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={config.color} stopOpacity={0.3}/>
                <stop offset="95%" stopColor={config.color} stopOpacity={0}/>
              </linearGradient>
            </defs>
            <YAxis hide={true} domain={['dataMin', 'dataMax']} />
            <Area 
              type="monotone" 
              dataKey="close" 
              stroke={config.color} 
              fill={`url(#color-${config.symbol})`} 
              strokeWidth={2} 
              dot={false}
              isAnimationActive={true}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default function CryptoMarket() {
  const [marketData, setMarketData] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchFullData = useCallback(async () => {
    try {
      // 1. Önce genel fiyat verilerini al
      const tickerRes = await axios.get('https://api.btcturk.com/api/v2/ticker');
      const filteredPairs = tickerRes.data.data.filter(c => COIN_CONFIGS[c.pair]);

      // 2. Her coin için son 24 saatlik grafik verisini (OHLC) çek
      // BtcTürk API'si için 1 saatlik (1h) mumları alıyoruz
      const fullData = await Promise.all(filteredPairs.map(async (coin) => {
        try {
          const ohlcRes = await axios.get(`https://api.btcturk.com/api/v2/graph/history/v1/klines?symbol=${coin.pair}&resolution=60`);
          // Grafik için sadece kapanış (close) fiyatlarını map'liyoruz
          const history = ohlcRes.data.map(item => ({ close: item.c }));
          return { ...coin, history };
        } catch (e) {
          return { ...coin, history: [] };
        }
      }));

      setMarketData(fullData);
      setLoading(false);
    } catch (err) {
      console.error("API Hatası:", err);
    }
  }, []);

  useEffect(() => {
    fetchFullData();
    const interval = setInterval(fetchFullData, 30000); // 30 saniyede bir tam güncelleme
    return () => clearInterval(interval);
  }, [fetchFullData]);

  if (loading) return <div className="loader">Veriler Yükleniyor...</div>;

  return (
    <div className="market-insight-wrapper">
      <div className="market-header">
        <h2 className="market-main-title">CRYPTO MARKET INSIGHTS</h2>
        <div className="live-indicator"><span>●</span> CANLI</div>
      </div>
      <div className="crypto-boxes-container">
        {marketData.map(coin => <CryptoBox key={coin.pair} coinData={coin} />)}
      </div>
    </div>
  );
}
